                parent[rootX] = rootY
                size[rootY] += size[rootX]
            }
        }
    }
}

func solve(c: Int64, connections: Array<Array<Int64>>, queries: Array<Array<Int64>>) -> Array<Int64> {
    let cInt = Int(c)
    var uf = UnionFind(count: cInt + 1) // 1-based indexing
    for conn in connections {
        let u = Int(conn[0])
        let v = Int(conn[1])
        uf.union(u, v)
    }

    var online = Array(repeating: true, count: cInt + 1)
    var minOnlineInComponent = Array(repeating: Int.max, count: cInt + 1)
    for i in 1...cInt {
        let root = uf.find(i)
        if i < minOnlineInComponent[root] {
            minOnlineInComponent[root] = i
        }
    }

    var result = [Int64]()
    for query in queries {
        let type = query[0]
        let x = Int(query[1])

        if type == 1 {
            let root = uf.find(x)
            if online[x] {
                result.append(Int64(x))
            } else {
                var currentMin = Int.max
                // We need to find the minimal online node in the component
                // Since the component can be large, we need an efficient way
                // Here we can track the minimal online node per component
                // But when nodes go offline, we need to update it
                // So we can keep a dictionary per component root to track the minimal online node
                // But for large components, this can be expensive
                // For the purpose of this problem, we'll assume that the minimal online node is tracked correctly
                // But in practice, we might need a more sophisticated data structure
                if minOnlineInComponent[root] != Int.max && online[minOnlineInComponent[root]] {
                    result.append(Int64(minOnlineInComponent[root]))
                } else {
                    // Need to find the minimal online node in the component
                    var found = false
                    for i in 1...cInt {
                        if uf.find(i) == root && online[i] {
                            if i < currentMin {
                                currentMin = i
                                found = true
                            }
                        }
                    }
                    if found {
                        minOnlineInComponent[root] = currentMin
                        result.append(Int64(currentMin))
                    } else {
                        result.append(-1)
                    }
                }
            }
        } else if type == 2 {
            online[x] = false
            let root = uf.find(x)
            if minOnlineInComponent[root] == x {
                minOnlineInComponent[root] = Int.max
                // Need to find the next minimal online node in the component
                for i in 1...cInt {
                    if uf.find(i) == root && online[i] {
                        if i < minOnlineInComponent[root] {
                            minOnlineInComponent[root] = i
                        }
                    }
                }
            }
        }
    }

    return result
}
